    clean_records_info = []
    pinyin_hints = []

    for i, (record_str, clean_rec) in enumerate(raw_clean_recs):
        b = bases[i]
        base_rec = b if base_counts[b] == 1 else clean_rec

        py_str = ""
        if has_pinyin and clean_rec:
            rec_pys = pypinyin.pinyin(clean_rec, heteronym=False, style=pypinyin.NORMAL)
